import React from 'react';
import logo from '../assets/aurelia-logo.png';

function Header() {
  return (
    <header className = "main-header">
        <div className = "top-row">
          <img className="title" src={logo} alt="Aurelia" />
          <div className="search">🔍</div>
        </div>
    <div className="bottom-row">
            <a>Women</a>
            <a>Men</a>
            <a>Accessories</a>
        </div>
    </header>
  );
}

export default Header;
